# test_compose.py
import pytest

from your_module import compose  # replace with the actual module name


def test_compose_happy_path_applies_functions_right_to_left():
    def double(x):
        return x * 2

    def square(x):
        return x**2

    composed = compose(square, double)

    assert composed(3) == 36  # square(double(3))


def test_compose_with_multiple_functions():
    def add_one(x):
        return x + 1

    def double(x):
        return x * 2

    def to_string(x):
        return f"value={x}"

    composed = compose(to_string, double, add_one)

    assert composed(4) == "value=10"  # to_string(double(add_one(4)))


def test_compose_preserves_call_order():
    calls = []

    def first(x):
        calls.append("first")
        return x + " first"

    def second(x):
        calls.append("second")
        return x + " second"

    def third(x):
        calls.append("third")
        return x + " third"

    composed = compose(first, second, third)

    result = composed("start")

    assert result == "start third second first"
    assert calls == ["third", "second", "first"]


def test_compose_with_single_function():
    def add_one(x):
        return x + 1

    composed = compose(add_one)

    assert composed(10) == 11


def test_compose_with_no_functions_returns_input_unchanged():
    value = {"key": "value"}

    composed = compose()

    assert composed(value) is value


def test_compose_propagates_exception_from_function():
    def raises_error(x):
        raise ValueError("bad input")

    def add_one(x):
        return x + 1

    composed = compose(add_one, raises_error)

    with pytest.raises(ValueError, match="bad input"):
        composed(10)


def test_compose_with_non_callable_raises_type_error_when_called():
    composed = compose(lambda x: x + 1, "not callable")

    with pytest.raises(TypeError):
        composed(10)


def test_compose_stops_execution_after_exception():
    calls = []

    def first(x):
        calls.append("first")
        return x

    def failing(x):
        calls.append("failing")
        raise RuntimeError("failure")

    def last(x):
        calls.append("last")
        return x

    composed = compose(first, failing, last)

    with pytest.raises(RuntimeError, match="failure"):
        composed("input")

    assert calls == ["last", "failing"]
